import React from 'react';
import { Link } from 'react-router-dom';
// './Services.css' फाईल तुमच्याकडे असल्याची खात्री करा, अन्यथा खालील <style> टॅग वापरा.

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", desc: "Modern, responsive websites built with React and Node.js.", color: "primary" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-paint-brush", desc: "Creative and user-friendly interface designs.", color: "danger" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Custom Android and iOS applications.", color: "success" },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-open", desc: "Expert help for academic projects and assignments.", color: "warning" },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", desc: "Professional presentations for business and college.", color: "info" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-alt", desc: "Detailed technical and business report writing.", color: "secondary" },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", desc: "Grow your online presence with social media ads.", color: "dark" },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", desc: "High-quality blog posts and creative writing.", color: "primary" }, // 'pink' ऐवजी 'primary' केला
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", desc: "Improve your website ranking on search engines.", color: "info" } // 'teal' ऐवजी 'info' केला
  ];

  return (
    <div className="services-page bg-light">
      {/* Header Section */}
      <header className="py-5 bg-dark text-white text-center shadow">
        <div className="container">
          <h1 className="fw-bold display-4">My Professional Services</h1>
          <p className="lead opacity-75">Tailored solutions for your digital and academic success.</p>
        </div>
      </header>

      {/* Services Grid */}
      <section className="container py-5">
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-md-4" key={service.id}>
              <div className="card h-100 border-0 shadow-sm p-4 text-center service-card shadow-hover">
                <div className={`mb-3 text-${service.color}`}>
                  <i className={`${service.icon} fa-3x`}></i>
                </div>
                <h4 className={`fw-bold text-dark`}>{service.title}</h4>
                <p className="text-muted small">{service.desc}</p>
                <Link to="/register" className={`btn btn-outline-${service.color} btn-sm mt-auto shadow-sm`}>
                  Get Started
                </Link>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* How I Work Section */}
      <section className="py-5 bg-white border-top shadow-sm">
        <div className="container text-center">
          <h2 className="fw-bold mb-5">How I Work?</h2>
          <div className="row g-4 justify-content-center">
            {[
              { title: 'Consultation', desc: 'Discussing requirements to ensure clarity.' },
              { title: 'Strategy & Design', desc: 'Creating a personalized plan for your project.' },
              { title: 'Final Delivery', desc: 'Timely delivery with professional support.' }
            ].map((step, index) => (
              <div className="col-md-4" key={index}>
                <div className="process-step p-3">
                  <div className="badge bg-primary rounded-circle mb-3 p-3 fs-5 shadow-sm">
                    0{index + 1}
                  </div>
                  <h5 className="fw-bold">{step.title}</h5>
                  <p className="text-muted small px-3">{step.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Internal CSS for missing hover effects */}
      <style>{`
        .service-card { transition: 0.3s ease; border-radius: 15px; }
        .service-card:hover { transform: translateY(-10px); box-shadow: 0 10px 20px rgba(0,0,0,0.1) !important; }
        .shadow-hover:hover { cursor: pointer; }
      `}</style>
    </div>
  );
}

export default Services;
